<issue_title>[bug-hunter] useSimpleEsqlQuery surfaces AbortError as
user-facing error state</issue_title>
<issue_description>## Impact
Components using `useSimpleEsqlQuery` can show a false error when a
request is intentionally canceled (for example, during rapid query/input
changes). This presents cancellation as a real failure (`"AbortError:
aborted"`), which is misleading and degrades UX.

## Reproduction Steps
1. Create a new minimal test file:
   ```bash
   cd peek
   cat > tests/unit/useSimpleEsqlQuery.abort-repro.test.ts <<'EOF'
   // `@vitest-environment` jsdom
   import React from "react";
   import { describe, it, expect, vi, beforeEach } from "vitest";
   import { renderHook, waitFor } from "`@testing-library/react`";
import { QueryClient, QueryClientProvider } from
"`@tanstack/react-query`";

import { useSimpleEsqlQuery } from "../../src/hooks/useSimpleEsqlQuery";
import { useConnectionStore } from "../../src/store/useConnectionStore";
   import type { ElasticsearchConnection } from "../../src/types";
   import { resetAllStores } from "../fixtures/test-utils";

   const mockExecute = vi.fn();
   vi.mock("../../src/services/perses/esqlDatasource", () => ({
     createPersesEsqlDatasource: () => ({ execute: mockExecute }),
   }));

   const MOCK_CONNECTION: ElasticsearchConnection = {
     url: "(localhost/redacted)
     auth: { type: "none" },
   };

   function createWrapper() {
const queryClient = new QueryClient({ defaultOptions: { queries: {
retry: false } } });
     return ({ children }: { children: React.ReactNode }) =>
React.createElement(QueryClientProvider, { client: queryClient },
children);
   }

   describe("repro: useSimpleEsqlQuery abort behavior", () => {
     beforeEach(() => {
       vi.clearAllMocks();
       resetAllStores();
       useConnectionStore.setState({ connection: MOCK_CONNECTION });
     });

it("should ignore AbortError instead of surfacing a user-facing error",
async () => {
mockExecute.mockRejectedValueOnce(new DOMException("aborted",
"AbortError"));

const { result } = renderHook(() => useSimpleEsqlQuery({ query: "FROM
index | LIMIT 1" }), {
         wrapper: createWrapper(),
       });

       await waitFor(() => {
         expect(result.current.loading).toBe(false);
       });

       expect(result.current.error).toBeNull();
     });
   });
   EOF
   ```
2. Run only this new test:
   ```bash
   npx vitest run tests/unit/useSimpleEsqlQuery.abort-repro.test.ts
   ```

## Expected vs Actual
**Expected:** Canceled requests (`AbortError`) are treated as non-errors
and do not populate `error`.

**Actual:** The hook returns a user-facing error string from the
canceled request:
```text
AssertionError: expected 'AbortError: aborted' to be null
+ Received: "AbortError: aborted"
```

## Failing Test
